const Synonyms = ({ synonyms }) => {
  const colors = [
    "text-[#f87171]",
    "text-[#60a5fa]",
    "text-[#34d399]",
    "text-[#a78bfa]",
    "text-[#fbbf24]",
    "text-[#f43f5e]",
    "text-[#3b82f6]",
    "text-[#10b981]",
    "text-[#8b5cf6]",
  ];
  return (
    <div className="flex flex-wrap gap-2 text-sm">
      {synonyms?.map((synonym, i) => (
        <span
          key={i}
          className={`px-2 py-1 rounded-md border border-white/10 font-medium ${colors[i % colors.length]} bg-white/5`}
        >
          {synonym}
        </span>
      ))}
    </div>
  );
};

export default Synonyms;
